from qiskit import QuantumCircuit
from qiskit.quantum_info import Statevector
import numpy as np
from typing import Dict, List

class StatevectorInspector:
    """Inspect statevectors for debugging."""

    def __init__(self, circuit: QuantumCircuit):
        self.circuit = circuit.remove_final_measurements(inplace=False)
        self.statevector = Statevector.from_instruction(self.circuit)

    def get_nonzero_amplitudes(self, threshold: float = 1e-10) -> Dict[str, Dict]:
        data = self.statevector.data
        n_qubits = int(np.log2(len(data)))
        result = {}

        for i, amp in enumerate(data):
            mag = abs(amp)
            if mag > threshold:
                basis = format(i, f'0{n_qubits}b')
                result[basis] = {
                    'amplitude': complex(amp),
                    'magnitude': mag,
                    'phase': np.angle(amp),
                    'phase_degrees': np.degrees(np.angle(amp)),
                    'probability': mag ** 2
                }
        return result

    def check_normalization(self) -> Dict:
        total_prob = sum(abs(a)**2 for a in self.statevector.data)
        return {
            'total_probability': total_prob,
            'is_normalized': abs(total_prob - 1.0) < 1e-10,
            'error': abs(total_prob - 1.0)
        }

    def get_dominant_states(self, top_n: int = 5) -> List[Dict]:
        amplitudes = self.get_nonzero_amplitudes()
        sorted_states = sorted(
            amplitudes.items(),
            key=lambda x: x[1]['probability'],
            reverse=True
        )
        return [
            {'state': state, **data}
            for state, data in sorted_states[:top_n]
        ]

    def print_debug_info(self):
        n_qubits = int(np.log2(len(self.statevector.data)))
        print(f"Statevector Debug Info ({n_qubits} qubits)")
        print("=" * 50)

        norm = self.check_normalization()
        print(f"Normalization: {'OK' if norm['is_normalized'] else 'ERROR'}")
        print(f"Total probability: {norm['total_probability']:.10f}")
        print()

        print("Dominant States:")
        for item in self.get_dominant_states():
            amp = item['amplitude']
            print(f"  |{item['state']}⟩: {amp:.4f}")
            print(f"    prob={item['probability']:.4f}, phase={item['phase_degrees']:.1f}deg")

from qiskit import QuantumCircuit
from qiskit.quantum_info import Statevector
import numpy as np
from typing import Dict, List

class StateComparisonDebugger:
    """Compare actual vs expected quantum states."""

    def __init__(self, tolerance: float = 1e-6):
        self.tolerance = tolerance

    def compare(self, actual: Statevector, expected: Statevector) -> Dict:
        a_data = actual.data
        e_data = expected.data

        if len(a_data) != len(e_data):
            return {'match': False, 'error': 'Dimension mismatch'}

        fidelity = abs(np.vdot(a_data, e_data))**2
        n = int(np.log2(len(a_data)))

        differences = []
        for i, (a, e) in enumerate(zip(a_data, e_data)):
            if abs(a - e) > self.tolerance:
                differences.append({
                    'state': format(i, f'0{n}b'),
                    'actual': complex(a),
                    'expected': complex(e)
                })

        phase_errors = self.detect_phase_errors(actual, expected)

        return {
            'match': fidelity > 1 - self.tolerance,
            'fidelity': fidelity,
            'num_differences': len(differences),
            'differences': differences[:5],
            'phase_errors': phase_errors,
            'suggestions': self.suggest_fixes(actual, expected)
        }

    def detect_phase_errors(self, actual: Statevector,
                            expected: Statevector) -> List[Dict]:
        a_data, e_data = actual.data, expected.data
        n = int(np.log2(len(a_data)))
        errors = []

        for i, (a, e) in enumerate(zip(a_data, e_data)):
            a_mag, e_mag = abs(a), abs(e)
            if abs(a_mag - e_mag) < self.tolerance and a_mag > self.tolerance:
                phase_diff = abs(np.angle(a) - np.angle(e))
                if phase_diff > self.tolerance:
                    errors.append({
                        'state': format(i, f'0{n}b'),
                        'actual_phase': np.angle(a),
                        'expected_phase': np.angle(e)
                    })
        return errors

    def check_bit_reversal(self, actual: Statevector,
                           expected: Statevector) -> Dict:
        a_data = actual.data
        e_data = expected.data
        n = int(np.log2(len(a_data)))

        reversed_data = np.zeros_like(a_data)
        for i in range(len(a_data)):
            rev_idx = int(format(i, f'0{n}b')[::-1], 2)
            reversed_data[rev_idx] = a_data[i]

        rev_fidelity = abs(np.vdot(reversed_data, e_data))**2
        return {
            'is_reversed': rev_fidelity > 0.99,
            'reversed_fidelity': rev_fidelity
        }

    def suggest_fixes(self, actual: Statevector,
                      expected: Statevector) -> List[str]:
        suggestions = []
        a_nonzero = sum(1 for a in actual.data if abs(a) > 1e-10)
        e_nonzero = sum(1 for e in expected.data if abs(e) > 1e-10)

        if a_nonzero == 1 and e_nonzero > 1:
            suggestions.append('Missing superposition: Add Hadamard gates')

        if self.check_bit_reversal(actual, expected)['is_reversed']:
            suggestions.append('Qubit order reversed: Check indexing convention')

        if self.detect_phase_errors(actual, expected):
            suggestions.append('Phase errors detected: Check Z/S/T/Rz gates')

        return suggestions

from qiskit import QuantumCircuit
from qiskit.quantum_info import Statevector
import numpy as np
from typing import List, Dict, Optional

class EvolutionTracer:
    """Trace state evolution through circuit."""

    def __init__(self, circuit: QuantumCircuit):
        self.circuit = circuit.remove_final_measurements(inplace=False)
        self.trace = []

    def run_trace(self) -> List[Dict]:
        self.trace = []
        partial = QuantumCircuit(self.circuit.num_qubits)
        n = self.circuit.num_qubits

        # Initial state
        sv = Statevector.from_instruction(partial)
        self.trace.append({
            'step': 0,
            'gate': 'initial',
            'qubits': [],
            'state': sv.data.copy(),
            'probabilities': {format(i, f'0{n}b'): p 
                            for i, p in enumerate(sv.probabilities()) if p > 1e-10}
        })

        for i, (inst, qargs, cargs) in enumerate(self.circuit.data):
            qubit_indices = [q._index for q in qargs]
            partial.append(inst, qubit_indices)
            sv = Statevector.from_instruction(partial)

            self.trace.append({
                'step': i + 1,
                'gate': inst.name,
                'qubits': qubit_indices,
                'state': sv.data.copy(),
                'probabilities': {format(j, f'0{n}b'): p 
                                for j, p in enumerate(sv.probabilities()) if p > 1e-10}
            })

        return self.trace

    def get_state_at(self, step: int) -> Dict:
        if not self.trace:
            self.run_trace()
        if step >= len(self.trace):
            raise IndexError(f"Step {step} does not exist")
        return self.trace[step]

    def find_divergence(self, expected_evolution: List[np.ndarray],
                        tolerance: float = 1e-6) -> Optional[int]:
        if not self.trace:
            self.run_trace()

        for i, (actual, expected) in enumerate(zip(self.trace, expected_evolution)):
            fidelity = abs(np.vdot(actual['state'], expected))**2
            if fidelity < 1 - tolerance:
                return i
        return None

    def print_trace(self, show_amplitudes: bool = True):
        if not self.trace:
            self.run_trace()

        n = self.circuit.num_qubits
        print(f"Evolution Trace ({n} qubits, {len(self.trace)} steps)")
        print("=" * 60)

        for entry in self.trace:
            qubits_str = f" on {entry['qubits']}" if entry['qubits'] else ""
            print(f"\nStep {entry['step']}: {entry['gate']}{qubits_str}")

            if show_amplitudes:
                for i, amp in enumerate(entry['state']):
                    if abs(amp) > 1e-10:
                        basis = format(i, f'0{n}b')
                        print(f"  |{basis}⟩: {amp:.4f} (p={abs(amp)**2:.4f})")
            else:
                states = list(entry['probabilities'].keys())
                print(f"  States: {', '.join(states)}")

from qiskit import QuantumCircuit
from qiskit.quantum_info import Statevector, DensityMatrix, partial_trace
import numpy as np
from typing import Dict, List, Tuple

class EntanglementDebugger:
    """Debug entanglement in quantum circuits."""

    def __init__(self, circuit: QuantumCircuit):
        self.circuit = circuit.remove_final_measurements(inplace=False)
        self.n_qubits = circuit.num_qubits
        self.sv = Statevector.from_instruction(self.circuit)
        self.dm = DensityMatrix(self.sv)

    def get_qubit_purity(self, qubit: int) -> float:
        trace_qubits = [i for i in range(self.n_qubits) if i != qubit]
        if trace_qubits:
            reduced = partial_trace(self.dm, trace_qubits)
        else:
            reduced = self.dm
        return float(np.real(np.trace(reduced.data @ reduced.data)))

    def check_pair_entanglement(self, q1: int, q2: int) -> Dict:
        trace_qubits = [i for i in range(self.n_qubits) if i not in (q1, q2)]
        if trace_qubits:
            reduced = partial_trace(self.dm, trace_qubits)
        else:
            reduced = self.dm

        purity = float(np.real(np.trace(reduced.data @ reduced.data)))
        is_entangled = purity < 0.99

        return {
            'qubits': (q1, q2),
            'purity': purity,
            'is_entangled': is_entangled
        }

    def get_entanglement_map(self) -> Dict[Tuple[int, int], bool]:
        ent_map = {}
        for i in range(self.n_qubits):
            for j in range(i + 1, self.n_qubits):
                result = self.check_pair_entanglement(i, j)
                ent_map[(i, j)] = result['is_entangled']
        return ent_map

    def verify_expected_entanglement(self,
            expected_pairs: List[Tuple[int, int]]) -> Dict:
        actual_map = self.get_entanglement_map()
        expected_set = set(tuple(sorted(p)) for p in expected_pairs)
        actual_set = set(k for k, v in actual_map.items() if v)

        missing = expected_set - actual_set
        unexpected = actual_set - expected_set

        return {
            'matches': len(missing) == 0 and len(unexpected) == 0,
            'expected': list(expected_set),
            'actual': list(actual_set),
            'missing_entanglement': list(missing),
            'unexpected_entanglement': list(unexpected)
        }
